export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(([x, y]) => cellKey(x, y)));
  const isAlive = (x: number, y: number): boolean =>
    aliveKeys.has(cellKey(x, y));
  const survivors = cells.filter(([x, y]) =>
    survivesGeneration(countAliveNeighbors(x, y, isAlive)),
  );
  const deadCandidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      if (!aliveKeys.has(k)) deadCandidates.set(k, [nx, ny]);
    }
  }
  const births: Cell[] = [];
  for (const [, [x, y]] of deadCandidates) {
    if (countAliveNeighbors(x, y, isAlive) === 3) births.push([x, y]);
  }
  return [...survivors, ...births];
}

